    Azure.ResourceManager.Foundations.ResourceUpdateModel<Asset, AssetProperties>
  >;
  delete is Extension.DeleteWithoutOkAsync<Extension.ScopeParameter, Asset>;
  list is Extension.ListByTarget<Extension.ScopeParameter, Asset>;
}

